{
  "module": "01-layout.md",
  "group": "01 — Layout & Container Components",
  "apiCount": 9,
  "apis": [
    {
      "name": "Flex",
      "purpose": "弹性布局容器，高效排列对齐子元素并分配剩余空间",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Column",
      "purpose": "沿垂直方向布局的容器，支持设置子组件间距和对齐",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "沿水平方向布局的容器，支持设置子组件间距和对齐",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序依次入栈，后一个覆盖前一个",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动的容器组件，子组件尺寸超出父组件时可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "List",
      "purpose": "列表容器，支持懒加载/预加载，适合连续多行呈现同类数据",
      "anchor": "list",
      "status": "found"
    },
    {
      "name": "Grid",
      "purpose": "网格容器，由行和列分割的单元格组成",
      "anchor": "grid",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分割不同内容块/内容元素",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，自动填充容器主轴方向空余部分",
      "anchor": "blank",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Flex 存在二次布局过程，对性能敏感的推荐使用 Column/Row 替代",
    "List/Grid 推荐搭配 LazyForEach 或带 virtualScroll 的 Repeat 实现懒加载",
    "Blank 仅当父组件为 Row/Column/Flex 时在主轴方向生效",
    "Flex 的 space 属性（FlexSpaceOptions）需 import { LengthMetrics } from '@kit.ArkUI'",
    "Divider 默认水平，通过 vertical(true) 切换为垂直分割线"
  ],
  "missingApis": []
}

{
  "module": "02-navigation.md",
  "group": "02 -- Navigation & Tabs",
  "apiCount": 7,
  "apis": [
    {
      "name": "Navigation",
      "purpose": "路由导航根视图容器，含标题栏、内容区、工具栏，配合 NavPathStack 进行页面路由",
      "anchor": "navigation",
      "status": "found"
    },
    {
      "name": "NavPathStack",
      "purpose": "Navigation 导航控制器，以栈结构管理子页面，提供 pushPath/pop/pushPathByName 等方法",
      "anchor": "navpathstack10",
      "status": "found"
    },
    {
      "name": "NavRouter",
      "purpose": "导航组件（已停止维护），默认提供点击响应处理，API 13 起废弃",
      "anchor": "navrouterdeprecated",
      "status": "found"
    },
    {
      "name": "Tabs",
      "purpose": "页签内容视图切换容器组件，通过页签切换内容视图",
      "anchor": "tabs",
      "status": "found"
    },
    {
      "name": "TabContent",
      "purpose": "Tabs 的子组件，对应一个切换页签的内容视图",
      "anchor": "tabcontent",
      "status": "found"
    },
    {
      "name": "Router",
      "purpose": "页面路由 API（不推荐），通过 url 跳转页面，API 18 起废弃",
      "anchor": "ohosrouter-页面路由不推荐",
      "status": "found"
    },
    {
      "name": "WindowStage",
      "purpose": "窗口管理器接口，管理 Window 实例，提供 loadContent/getMainWindow/createSubWindow 等能力",
      "anchor": "interface-windowstage",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Navigation + NavPathStack 是推荐的页面路由方案（API 10+）；@ohos.router（API 18 废弃）和 NavRouter（API 13 废弃）不应在新代码中使用",
    "NavPathStack 定义在 Navigation 组件文档内部，无独立文档文件",
    "WindowStage 是 @ohos.window 模块的 Interface，在 UIAbility.onWindowStageCreate() 中通过参数获取实例",
    "Navigation 推荐使用 navDestination 属性 + NavPathStack 进行声明式路由，替代旧的 NavRouter 方式"
  ],
  "missingApis": []
}

{
  "module": "03-controls.md",
  "group": "03 — Controls & Input",
  "apiCount": 11,
  "apis": [
    {
      "name": "Button",
      "purpose": "按钮组件，支持三种构造方式：纯 label、含子组件、空按钮；支持 ButtonType、ButtonStyleMode、stateEffect 等配置",
      "anchor": "button",
      "status": "found"
    },
    {
      "name": "Text",
      "purpose": "文本显示组件，支持字体样式、文本溢出省略、行高、多行截断、图文混排（Span/ImageSpan）",
      "anchor": "text",
      "status": "found"
    },
    {
      "name": "TextInput",
      "purpose": "单行文本输入框，支持 placeholder、InputType 键盘类型、光标控制、双向绑定",
      "anchor": "textinput",
      "status": "found"
    },
    {
      "name": "TextArea",
      "purpose": "多行文本输入框，自适应内容高度，支持 maxLines、计数器、自定义键盘",
      "anchor": "textarea",
      "status": "found"
    },
    {
      "name": "Image",
      "purpose": "图片组件，支持 png/jpg/gif/svg/webp/heif/tiff 格式及 PixelMap/DrawableDescriptor 数据源",
      "anchor": "image",
      "status": "found"
    },
    {
      "name": "Checkbox",
      "purpose": "多选框组件，支持圆形/圆角方形样式、选中状态双向绑定、自定义选中样式",
      "anchor": "checkbox",
      "status": "found"
    },
    {
      "name": "LoadingProgress",
      "purpose": "加载动效组件，支持前景色设置和动画显示控制（enableLoading），API 8 起默认为彗星形样式",
      "anchor": "loadingprogress",
      "status": "found"
    },
    {
      "name": "Progress",
      "purpose": "进度条组件，提供 Linear/Ring/Eclipse/ScaleRing/Capsule 五种样式，支持进度平滑动效",
      "anchor": "progress",
      "status": "found"
    },
    {
      "name": "Toggle",
      "purpose": "开关组件，支持 Switch/Checkbox/Button 三种样式，用于二选一场景",
      "anchor": "toggle",
      "status": "found"
    },
    {
      "name": "Select",
      "purpose": "下拉选择菜单，支持图标与 Symbol 图标选项、自定义菜单样式、避让策略",
      "anchor": "select",
      "status": "found"
    },
    {
      "name": "Span",
      "purpose": "Text 子组件，用于行内文本独立样式设置，支持 decoration/letterSpacing/fontColor 等文本属性",
      "anchor": "span",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Image 源文件位于 11_图片与视频 目录，不在分配的 09/10/12 子目录中，通过 fallback 定位",
    "所有 11 个组件均为 ArkUI 内置组件，无需 import 导入",
    "Progress 的 ProgressStyle 从 API 8 起废弃，建议使用 ProgressType 替代",
    "Span 不支持通用属性，仅支持专用文本属性，从 API 10 起可继承父组件 Text 部分属性",
    "Toggle 仅在 ToggleType.Button 时允许包含子组件"
  ],
  "missingApis": []
}

{
  "module": "04-dialogs.md",
  "group": "04 -- Dialogs & Bottom Sheets",
  "apiCount": 6,
  "apis": [
    {
      "name": "bindSheet",
      "purpose": "为组件绑定半模态页面（Bottom Sheet），支持多挡位高度与多种显示类型",
      "anchor": "#bindsheet",
      "status": "found"
    },
    {
      "name": "CustomDialog",
      "purpose": "通过CustomDialogController + @CustomDialog装饰器实现完全自定义弹窗",
      "anchor": "#customdialog",
      "status": "found"
    },
    {
      "name": "AlertDialog",
      "purpose": "显示带标题、内容、按钮的警告弹窗",
      "anchor": "#alertdialog",
      "status": "found"
    },
    {
      "name": "ActionSheet",
      "purpose": "显示列表选择弹窗（Action Sheet），从底部或指定位置弹出选项列表",
      "anchor": "#actionsheet",
      "status": "found"
    },
    {
      "name": "Menu",
      "purpose": "垂直列表菜单容器，需配合bindMenu或bindContextMenu使用",
      "anchor": "#menu",
      "status": "found"
    },
    {
      "name": "ContextMenu",
      "purpose": "通过bindContextMenu绑定的上下文菜单的关闭控制",
      "anchor": "#contextmenu",
      "status": "found"
    }
  ],
  "notableFindings": [
    "CustomDialog 优先于 AlertDialog/ActionSheet，更灵活可控",
    "bindSheet 是 Bottom Sheet 的推荐方案，支持 SheetType.BOTTOM/CENTER/POPOVER/SIDE 四种样式",
    "ContextMenu.close() 在 API 18 废弃，需迁移到 UIContext.getContextMenuController().close()",
    "AlertDialog/ActionSheet/bindSheet 均依赖 UI 执行上下文，需要 getUIContext() 可用",
    "bindSheet 的离场动效不支持打断，动效执行期间无法响应其他手势"
  ],
  "missingApis": []
}

{
  "module": "06-persistence.md",
  "group": "06 — Data Persistence",
  "apiCount": 6,
  "apis": [
    {
      "name": "preferences (data.preferences)",
      "purpose": "轻量级 KV 键值型用户首选项持久化",
      "anchor": "preferences-data-preferences",
      "status": "found"
    },
    {
      "name": "relationalStore (data.relationalStore)",
      "purpose": "基于 SQLite 的本地关系型数据库",
      "anchor": "relationalstore-data-relationalstore",
      "status": "found"
    },
    {
      "name": "kvStore (data.distributedKVStore)",
      "purpose": "分布式键值数据库，支持多设备间端端同步",
      "anchor": "kvstore-data-distributedkvstore",
      "status": "found"
    },
    {
      "name": "RdbStore",
      "purpose": "关系型数据库管理接口，提供 insert/query/update/delete 等操作",
      "anchor": "rdbstore",
      "status": "found"
    },
    {
      "name": "ValueType",
      "purpose": "表示允许的数据字段类型，在不同模块中有不同定义",
      "anchor": "valuetype",
      "status": "found"
    },
    {
      "name": "ResultSet",
      "purpose": "关系型数据库查询结果集，提供行遍历和列值读取",
      "anchor": "resultset",
      "status": "found"
    }
  ],
  "notableFindings": [
    "ValueType 在 preferences/relationalStore/commonType 三模块中定义不同，需注意上下文选用",
    "preferences 从 API 18 起支持 XML 和 GSKV 两种存储模式，GSKV 模式实时落盘无需 flush",
    "relationalStore 单条数据建议不超过 2MB，单次查询不超过 5000 条",
    "distributedKVStore 支持 SingleKVStore 和 DeviceKVStore 两种数据库类型",
    "preferences 不支持多进程并发，有文件损坏和数据丢失风险"
  ],
  "missingApis": []
}

