  "module": "07-media.md",
  "group": "07 — Media & Image Picker",
  "apiCount": 8,
  "apis": [
    {
      "name": "PhotoViewPicker",
      "purpose": "System photo/video picker that returns permanently authorized URIs",
      "anchor": "photoviewpicker",
      "status": "found"
    },
    {
      "name": "CameraManager",
      "purpose": "Camera device management: query cameras, create inputs/outputs, manage sessions",
      "anchor": "cameramanager",
      "status": "found"
    },
    {
      "name": "CameraInput",
      "purpose": "Camera input control: open/close camera device with optional secure mode",
      "anchor": "camerainput",
      "status": "found"
    },
    {
      "name": "ImageReceiver",
      "purpose": "Receive raw image frames from a Surface (e.g. camera preview stream)",
      "anchor": "imagereceiver",
      "status": "found"
    },
    {
      "name": "ImageSource",
      "purpose": "Decode images to PixelMap/Picture from file, fd, or buffer; read image metadata",
      "anchor": "imagesource",
      "status": "found"
    },
    {
      "name": "ImagePacker",
      "purpose": "Encode PixelMap/ImageSource/Picture to compressed file or memory buffer (JPEG/PNG/WebP/HEIC/GIF)",
      "anchor": "imagepacker",
      "status": "found"
    },
    {
      "name": "fileIo",
      "purpose": "App-sandbox file system operations: open, read, write, close, stat, mkdir, listFile, copy, unlink",
      "anchor": "fileio",
      "status": "found"
